/* masked owned-storage comparator (used by datac-probe + CHK_OWNED_RELOC):
 * every byte outside the reloc slots must match; slot bytes legitimately
 * differ (pre-reloc placeholder here vs relocated pointer in the image). */
int obj3_owned_region_cmp(const obj3_owned_t *o, const unsigned char *image_base)
{
    const unsigned char *img = image_base + o->off;
    const unsigned char *own = (const unsigned char *)o->ptr;
    for (uint32_t b = 0; b < o->size; b++) {
        uint32_t k, masked = 0;
        for (k = 0; k < o->n_reloc_slots; k++)
            if (b >= o->reloc_slots[k] && b < o->reloc_slots[k] + 4u) { masked = 1; break; }
        if (!masked && img[b] != own[b])
            return (int)b + 1;
    }
    return 0;
}
